const b = ($json.body) ? $json.body : $json;
const honeypot = String(b.company || '').trim();
const email = String(b.email || '').trim();
const form = b.form || 'lead';
const isReferral = form === 'referral';
const isConfig = form === 'configurador';
const isDownload = form === 'descarga';
const table = isReferral ? 'referidos' : 'leads';
const skip = honeypot.length > 0 || !email;

let record;
if (isReferral) {
  record = {
    nombre: b.nombre || null, email: email, telefono: b.telefono || null,
    tipo: b.tipo || null, zona: b.zona || null, mensaje: b.mensaje || null,
    idioma: b.idioma || 'es', utm_source: b.utm_source || null,
    utm_campaign: b.utm_campaign || null, consentimiento: !!b.consentimiento,
  };
} else if (isConfig) {
  record = {
    nombre: b.nombre || null, email: email, telefono: b.telefono || null,
    idioma: b.idioma || 'es', tipo_interes: b.uso_proyecto || null, cta: 'configurador',
    uso_proyecto: b.uso_proyecto || null, tipo_terreno: b.tipo_terreno || null,
    requerimientos: b.requerimientos || null, mensaje: b.requerimientos || null,
    utm_source: b.utm_source || null, utm_medium: b.utm_medium || null,
    utm_campaign: b.utm_campaign || null, utm_content: b.utm_content || null,
    utm_term: b.utm_term || null, referrer: b.referrer || null,
    landing_path: b.landing_path || null, consentimiento: !!b.consentimiento,
  };
} else if (isDownload) {
  record = {
    nombre: b.nombre || null, email: email, telefono: b.telefono || null,
    idioma: b.idioma || 'es', tipo_interes: 'descarga', cta: 'descarga_catalogo',
    mensaje: 'Descargo el catalogo tecnico (PDF)',
    utm_source: b.utm_source || null, utm_medium: b.utm_medium || null,
    utm_campaign: b.utm_campaign || null, utm_content: b.utm_content || null,
    utm_term: b.utm_term || null, referrer: b.referrer || null,
    landing_path: b.landing_path || null, consentimiento: !!b.consentimiento,
  };
} else {
  record = {
    nombre: b.nombre || null, email: email, telefono: b.telefono || null,
    idioma: b.idioma || 'es', tipo_interes: b.tipo_interes || null,
    cta: b.cta || 'lead_form', mensaje: b.mensaje || null,
    utm_source: b.utm_source || null, utm_medium: b.utm_medium || null,
    utm_campaign: b.utm_campaign || null, utm_content: b.utm_content || null,
    utm_term: b.utm_term || null, referrer: b.referrer || null,
    landing_path: b.landing_path || null, consentimiento: !!b.consentimiento,
  };
}

let titulo = '🔥 Nuevo LEAD COUVA 6x6';
if (isReferral) titulo = '🤝 Nuevo SOCIO referidor';
else if (isConfig) titulo = '🏗️ Nuevo CONFIGURADOR (proyecto a medida)';
else if (isDownload) titulo = '📄 Nueva DESCARGA de catalogo';
const asunto = titulo + ' - ' + (b.nombre || 'sin nombre');
const cuerpo = Object.entries(record).map(function(e){return e[0] + ': ' + (e[1] == null ? '' : e[1]);}).join('\n');
return { table: table, record: record, skip: skip, asunto: asunto, cuerpo: cuerpo, isReferral: isReferral };

const p = $('Preparar datos').item.json;
const r = p.record || {};
return {
  fecha: new Date().toISOString(),
  formulario: p.isReferral ? 'referido' : 'lead',
  nombre: r.nombre || '',
  email: r.email || '',
  telefono: r.telefono || '',
  detalle: p.isReferral ? (r.tipo || '') : (r.tipo_interes || ''),
  mensaje: r.mensaje || '',
  idioma: r.idioma || '',
  utm_source: r.utm_source || '',
  utm_campaign: r.utm_campaign || '',
};
